app.post("/api/v1/auth/send-code", async (req, res) => {
  try {
    const { email } = req.body;
    if (!email || !email.includes("@")) {
      res.status(400).json({ error: "\u8BF7\u8F93\u5165\u6709\u6548\u7684\u90AE\u7BB1\u5730\u5740" });
      return;
    }
    const code = Math.floor(1e5 + Math.random() * 9e5).toString();
    const expiresAt = new Date(Date.now() + 5 * 60 * 1e3);
    await insertAuthCode(email, code, expiresAt);
    const { sendLoginCode: sendLoginCode2 } = await Promise.resolve().then(() => (init_email(), email_exports));
    await sendLoginCode2(email, code);
    res.json({ success: true });
  } catch (err) {
    console.error("POST /auth/send-code error:", err);
    res.status(500).json({ error: err.message });
  }
});
app.post("/api/v1/auth/verify-code", async (req, res) => {
  try {
    const { email, code } = req.body;
    if (!email || !code) {
      res.status(400).json({ error: "\u8BF7\u8F93\u5165\u90AE\u7BB1\u548C\u9A8C\u8BC1\u7801" });
      return;
    }
    const authCode = await findValidAuthCode(email, code);
    if (!authCode) {
      res.status(400).json({ error: "\u9A8C\u8BC1\u7801\u9519\u8BEF\u6216\u5DF2\u8FC7\u671F" });
      return;
    }
    await deleteAuthCode(authCode.id);
    const { supabaseAdmin: supabaseAdmin2 } = await Promise.resolve().then(() => (init_supabase(), supabase_exports));
    let userId;
    const { data: { users }, error: listError } = await supabaseAdmin2.auth.admin.listUsers();
    if (listError) throw listError;
    const existingUser = users.find((u) => u.email === email);
    if (existingUser) {
      userId = existingUser.id;
    } else {
      const { data: newUser, error: createError } = await supabaseAdmin2.auth.admin.createUser({
        email,
        email_confirm: true
      });
      if (createError) throw createError;
      userId = newUser.user.id;
    }
    const token = crypto2.randomBytes(32).toString("hex");
    const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1e3);
    await createSession(token, userId, email, expiresAt);
    res.json({ success: true, token, user: { id: userId, email } });
  } catch (err) {
    console.error("POST /auth/verify-code error:", err);
    res.status(500).json({ error: err.message });
  }
});
app.post("/api/v1/migrate-device-data", async (req, res) => {
  try {
    const { device_id } = req.body;
    if (!req.userId) {
      res.status(401).json({ error: "\u8BF7\u5148\u767B\u5F55" });
      return;
    }
    if (!device_id) {
      res.status(400).json({ error: "\u7F3A\u5C11 device_id" });
      return;
    }
    const dbConn = await getDb();
    const result = await dbConn`
      UPDATE dreamdis_dreams
      SET user_id = ${req.userId}
      WHERE device_id = ${device_id} AND user_id IS NULL
    `;
    res.json({ migrated: result.count });
  } catch (err) {
    console.error("POST /migrate-device-data error:", err);
    res.status(500).json({ error: err.message });
  }
});
